import React from "react";

function AboutPage() {
  return (
    <div className="card">
      <h2>À propos</h2>
      <p>
        Cette application a été réalisée dans le cadre du TP 10 sur React. Elle
        montre l'utilisation des hooks principaux : useState, useEffect,
        useContext, useReducer, useMemo, useCallback et useRef.
      </p>
    </div>
  );
}

export default AboutPage;
